// 32-bit opcodes (and their bit patterns and masks)
#[allow(non_camel_case_types)]
#[allow(clippy::unusual_byte_groupings)] // patterns are grouped into 4-bit instruction fields for readability
#[repr(u32)] // several discriminants exceed i32::MAX; pin the backing type so the enum is portable to 32-bit hosts
pub enum ArmT32OpcodePattern_32Bit {
    Bl_T1            = 0b1111_0000_0000_0000_1101_0000_0000_0000, // mask: 0b1111_1000_0000_0000_1101_0000_0000_0000
    Dmb_T1           = 0b1111_0011_1011_1111_1000_1111_0101_0000, // mask: 0b1111_1111_1111_1111_1111_1111_1111_0000 // NOTE: the mask excluding the "(#)" bits is: 0b1111_1111_1111_0000_1101_0000_1111_0000
    Dsb_T1           = 0b1111_0011_1011_1111_1000_1111_0100_0000, // mask: 0b1111_1111_1111_1111_1111_1111_1111_0000 // NOTE: the mask excluding the "(#)" bits is: 0b1111_1111_1111_0000_1101_0000_1111_0000
    Isb_T1           = 0b1111_0011_1011_1111_1000_1111_0110_0000, // mask: 0b1111_1111_1111_1111_1111_1111_1111_0000 // NOTE: the mask excluding the "(#)" bits is: 0b1111_1111_1111_0000_1101_0000_1111_0000
    Mrs_T1           = 0b1111_0011_1110_1111_1000_0000_0000_0000, // mask: 0b1111_1111_1111_1111_1111_0000_0000_0000 // NOTE: the mask excluding the "(#)" bits is: 0b1111_1111_1110_0000_1101_0000_0000_0000
    Msr_Register_T1  = 0b1111_0011_1000_0000_1000_1000_0000_0000, // mask: 0b1111_1111_1111_0000_1111_1111_0000_0000 // NOTE: the mask excluding the "(#)" bits is: 0b1111_1111_1110_0000_1101_0000_0000_0000
    Udf_T2           = 0b1111_0111_1111_0000_1010_0000_0000_0000, // mask: 0b1111_1111_1111_0000_1111_0000_0000_0000

    // ---- ARMv7-M (Thumb-2) additions ----
    Mov_Immediate_T3 = 0b1111_0010_0100_0000_0000_0000_0000_0000, // MOVW; mask: 0b1111_1011_1111_0000_1000_0000_0000_0000 (imm16 = imm4:i:imm3:imm8)
    Movt_T1          = 0b1111_0010_1100_0000_0000_0000_0000_0000, // MOVT; mask: 0b1111_1011_1111_0000_1000_0000_0000_0000
    Mul_T2           = 0b1111_1011_0000_0000_1111_0000_0000_0000, // mask: 0b1111_1111_1111_0000_1111_0000_1111_0000
    Mla_T1           = 0b1111_1011_0000_0000_0000_0000_0000_0000, // mask: 0b1111_1111_1111_0000_0000_0000_1111_0000 (Ra != 0b1111, else MUL)
    Mls_T1           = 0b1111_1011_0000_0000_0000_0000_0001_0000, // mask: 0b1111_1111_1111_0000_0000_0000_1111_0000
    Sdiv_T1          = 0b1111_1011_1001_0000_1111_0000_1111_0000, // mask: 0b1111_1111_1111_0000_1111_0000_1111_0000
    Udiv_T1          = 0b1111_1011_1011_0000_1111_0000_1111_0000, // mask: 0b1111_1111_1111_0000_1111_0000_1111_0000
    Clz_T1           = 0b1111_1010_1011_0000_1111_0000_1000_0000, // mask: 0b1111_1111_1111_0000_1111_0000_1111_0000 (Rn==Rm in bits 19:16 and 3:0)
    Rbit_T1          = 0b1111_1010_1001_0000_1111_0000_1010_0000, // mask: 0b1111_1111_1111_0000_1111_0000_1111_0000 (Rm in bits 19:16 and 3:0)

    // ---- ARMv7-M (Thumb-2) batch M7b: bitfield + wide load/store ----
    Ubfx_T1          = 0b1111_0011_1100_0000_0000_0000_0000_0000, // mask: 0b1111_1111_1111_0000_1000_0000_0010_0000 (lsb=imm3:imm2, widthm1)
    Sbfx_T1          = 0b1111_0011_0100_0000_0000_0000_0000_0000, // mask: 0b1111_1111_1111_0000_1000_0000_0010_0000
    Bfi_T1           = 0b1111_0011_0110_0000_0000_0000_0000_0000, // mask: 0b1111_1111_1111_0000_1000_0000_0010_0000 (Rn==0b1111 => BFC; msb in bits 4:0)
    Ldr_Immediate_T3 = 0b1111_1000_1101_0000_0000_0000_0000_0000, // LDR.W; mask: 0b1111_1111_1111_0000_0000_0000_0000_0000 (imm12)
    Str_Immediate_T3 = 0b1111_1000_1100_0000_0000_0000_0000_0000, // STR.W; mask: 0b1111_1111_1111_0000_0000_0000_0000_0000 (imm12)

    // ---- ARMv7-M batch M7c: synchronization (exclusive access) + table branch ----
    Ldrex_T1         = 0b1110_1000_0101_0000_0000_1111_0000_0000, // LDREX  Rt,[Rn,#imm]; mask 0b1111_1111_1111_0000_0000_1111_0000_0000 (imm8 = offset/4)
    Strex_T1         = 0b1110_1000_0100_0000_0000_0000_0000_0000, // STREX  Rd,Rt,[Rn,#imm]; mask 0b1111_1111_1111_0000_0000_0000_0000_0000 (imm8 = offset/4)
    Ldrexb_T1        = 0b1110_1000_1101_0000_0000_1111_0100_1111, // LDREXB Rt,[Rn]; mask 0b1111_1111_1111_0000_0000_1111_1111_1111 (Rt in 15:12 variable)
    Strexb_T1        = 0b1110_1000_1100_0000_0000_1111_0100_0000, // STREXB Rd,Rt,[Rn]; mask 0b1111_1111_1111_0000_0000_1111_1111_0000 (Rt in 15:12 variable)
    Ldrexh_T1        = 0b1110_1000_1101_0000_0000_1111_0101_1111, // LDREXH Rt,[Rn]; mask 0b1111_1111_1111_0000_0000_1111_1111_1111
    Strexh_T1        = 0b1110_1000_1100_0000_0000_1111_0101_0000, // STREXH Rd,Rt,[Rn]; mask 0b1111_1111_1111_0000_0000_1111_1111_0000
    Clrex_T1         = 0b1111_0011_1011_1111_1000_1111_0010_0000, // CLREX (option nibble SBO=1111 OR'd in at encode); mask 0b1111_1111_1111_1111_1111_1111_1111_0000
    Tbb_T1           = 0b1110_1000_1101_0000_1111_0000_0000_0000, // TBB [Rn,Rm]; mask 0b1111_1111_1111_0000_1111_1111_1111_0000
    Tbh_T1           = 0b1110_1000_1101_0000_1111_0000_0001_0000, // TBH [Rn,Rm,LSL #1]; mask 0b1111_1111_1111_0000_1111_1111_1111_0000

    // ---- ARMv8-M / speculation-barrier hint ----
    Csdb_T1          = 0b1111_0011_1010_1111_1000_0000_0001_0100, // CSDB (Consumption of Speculative Data Barrier); fully fixed 0xF3AF8014

    // ---- ARMv8-M Security Extension (TrustZone-M) ----
    Sg_T1            = 0b1110_1001_0111_1111_1110_1001_0111_1111, // SG (Secure Gateway); fully fixed 0xE97FE97F
    Tt_T1            = 0b1110_1000_0100_0000_1111_0000_0000_0000, // TT/TTT/TTA/TTAT Rd,Rn; mask 0b1111_1111_1111_0000_1111_0000_0011_1111 (Rd[11:8], A[7], T[6])
    Vlstm_T1         = 0b1110_1100_0010_0000_0000_1010_0000_0000, // VLSTM Rn (lazy FP save); mask 0b1111_1111_1111_0000_1111_1111_1111_1111
    Vlldm_T1         = 0b1110_1100_0011_0000_0000_1010_0000_0000, // VLLDM Rn (lazy FP restore); mask 0b1111_1111_1111_0000_1111_1111_1111_1111
}
